class Solution:
    def checkPossibility(self, nums):
        n = len(nums)
        def ok(arr):
            return all(arr[i] <= arr[i + 1] for i in range(len(arr) - 1))
        if ok(nums):
            return True
        for i in range(n):
            for nv in set(nums + [-100001, 100001]):
                arr = nums[:]
                arr[i] = nv
                if ok(arr):
                    return True
        return False

